#include <stdio.h>
#include <stdint.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; scanf("%d", &N);
        uint64_t xr = 0, val;
        for(int i=0;i<N;i++){
            scanf("%llu", &val);
            xr ^= val;
        }
        printf("%llu\n", xr << 1);
    }
    return 0;
}

